module RefModule (
	input clk,
	input reset,
	input enable_n,
	input [11:0] data_in,
	output reg [11:0] data_out
);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
	if (reset)
		data_out <= 12'b000000000000;
	else if (~enable_n)
		data_out <= data_in;
end

endmodule
